/** Encode a generated CSIL record to canonical CBOR bytes. */
fun <T> encode(value: T): ByteArray = CsilCbor.encode(csilToCborValue(value))

private fun csilToCborValue(value: Any?): CborValue = when (value) {
    null -> CborValue.CNull
    is Task -> value.toCborValue()
    is SubmitTaskRequest -> value.toCborValue()
    is SubmitTaskResponse -> value.toCborValue()
    is GetTaskStateByIDRequest -> value.toCborValue()
    is GetTaskStateByIDResponse -> value.toCborValue()
    is GetNextTaskRequest -> value.toCborValue()
    is GetNextTaskResponse -> value.toCborValue()
    is CompleteTaskRequest -> value.toCborValue()
    is CompleteTaskResponse -> value.toCborValue()
    is UpdateTaskRequest -> value.toCborValue()
    is UpdateTaskResponse -> value.toCborValue()
    is CancelTaskRequest -> value.toCborValue()
    is CancelTaskResponse -> value.toCborValue()
    is CleanUpTimedOutRequest -> value.toCborValue()
    is CleanUpTimedOutResponse -> value.toCborValue()
    is GetQueuesRequest -> value.toCborValue()
    is GetQueuesResponse -> value.toCborValue()
    is GetQueueTaskCountsRequest -> value.toCborValue()
    is GetQueueTaskCountsResponse -> value.toCborValue()
    is GetTaskStateCountsRequest -> value.toCborValue()
    is GetTaskStateCountsResponse -> value.toCborValue()
    is QueueAndStateCounts -> value.toCborValue()
    is GetQueueAndStateCountsRequest -> value.toCborValue()
    is GetQueueAndStateCountsResponse -> value.toCborValue()
    is ServiceError -> value.toCborValue()
    else -> throw CborError("no CSIL CBOR codec for ${value::class}")
}

/** Decode canonical CBOR bytes into a generated CSIL record of type [T]. */
inline fun <reified T> decode(bytes: ByteArray): T =
    csilFromCborValue(T::class, CsilCbor.decode(bytes)) as T

fun csilFromCborValue(type: kotlin.reflect.KClass<*>, cbor: CborValue): Any = when (type) {
    Task::class -> taskFromCborValue(cbor)
    SubmitTaskRequest::class -> submitTaskRequestFromCborValue(cbor)
    SubmitTaskResponse::class -> submitTaskResponseFromCborValue(cbor)
    GetTaskStateByIDRequest::class -> getTaskStateByIDRequestFromCborValue(cbor)
    GetTaskStateByIDResponse::class -> getTaskStateByIDResponseFromCborValue(cbor)
    GetNextTaskRequest::class -> getNextTaskRequestFromCborValue(cbor)
    GetNextTaskResponse::class -> getNextTaskResponseFromCborValue(cbor)
    CompleteTaskRequest::class -> completeTaskRequestFromCborValue(cbor)
    CompleteTaskResponse::class -> completeTaskResponseFromCborValue(cbor)
    UpdateTaskRequest::class -> updateTaskRequestFromCborValue(cbor)
    UpdateTaskResponse::class -> updateTaskResponseFromCborValue(cbor)
    CancelTaskRequest::class -> cancelTaskRequestFromCborValue(cbor)
    CancelTaskResponse::class -> cancelTaskResponseFromCborValue(cbor)
    CleanUpTimedOutRequest::class -> cleanUpTimedOutRequestFromCborValue(cbor)
    CleanUpTimedOutResponse::class -> cleanUpTimedOutResponseFromCborValue(cbor)
    GetQueuesRequest::class -> getQueuesRequestFromCborValue(cbor)
    GetQueuesResponse::class -> getQueuesResponseFromCborValue(cbor)
    GetQueueTaskCountsRequest::class -> getQueueTaskCountsRequestFromCborValue(cbor)
    GetQueueTaskCountsResponse::class -> getQueueTaskCountsResponseFromCborValue(cbor)
    GetTaskStateCountsRequest::class -> getTaskStateCountsRequestFromCborValue(cbor)
    GetTaskStateCountsResponse::class -> getTaskStateCountsResponseFromCborValue(cbor)
    QueueAndStateCounts::class -> queueAndStateCountsFromCborValue(cbor)
    GetQueueAndStateCountsRequest::class -> getQueueAndStateCountsRequestFromCborValue(cbor)
    GetQueueAndStateCountsResponse::class -> getQueueAndStateCountsResponseFromCborValue(cbor)
    ServiceError::class -> serviceErrorFromCborValue(cbor)
    else -> throw CborError("no CSIL CBOR codec for $type")
}
